import type { Metadata } from "next";
import TransactionsScreen from "./TransactionsScreen";

export const metadata: Metadata = {
  title: "取引明細 | ぐんじょう銀行",
  description: "普通預金口座の取引履歴。期間・カテゴリ・金額・キーワードで絞り込み、CSV/PDF で出力できます。",
};

export default function TransactionsPage() {
  return <TransactionsScreen />;
}

// Mock account-statement data + domain helpers for the 取引明細 screen.
// Deterministic generation (seeded) so SSR and client render identically —
// avoids hydration mismatch from Math.random().

export type TxnCategory =
  | "給与"
  | "振込"
  | "引落"
  | "ATM出金"
  | "カード"
  | "手数料"
  | "利息";

export type TxnDirection = "in" | "out";

export interface Transaction {
  id: string;
  /** ISO date (yyyy-mm-dd). */
  date: string;
  /** 摘要 / 相手先. */
  description: string;
  category: TxnCategory;
  direction: TxnDirection;
  /** Positive magnitude in yen. */
  amount: number;
  /** Running balance AFTER this transaction (chronological). Filled by buildLedger. */
  balance: number;
}

export const CATEGORIES: TxnCategory[] = [
  "給与",
  "振込",
  "引落",
  "ATM出金",
  "カード",
  "手数料",
  "利息",
];

/** Maps each category to a Badge tone + whether it is typically in/out. */
export const CATEGORY_META: Record<
  TxnCategory,
  { tone: "success" | "info" | "warning" | "secondary" | "destructive" | "outline"; defaultDir: TxnDirection }
> = {
  給与: { tone: "success", defaultDir: "in" },
  振込: { tone: "info", defaultDir: "in" },
  引落: { tone: "warning", defaultDir: "out" },
  ATM出金: { tone: "secondary", defaultDir: "out" },
  カード: { tone: "outline", defaultDir: "out" },
  手数料: { tone: "destructive", defaultDir: "out" },
  利息: { tone: "success", defaultDir: "in" },
};

// --- deterministic PRNG (mulberry32) -------------------------------------
function mulberry32(seed: number) {
  return function () {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

interface Template {
  category: TxnCategory;
  direction: TxnDirection;
  descriptions: string[];
  min: number;
  max: number;
  weight: number;
}

const TEMPLATES: Template[] = [
  { category: "給与", direction: "in", descriptions: ["給与振込 カ）グンジョウ商事", "賞与振込 カ）グンジョウ商事"], min: 180000, max: 320000, weight: 2 },
  { category: "振込", direction: "in", descriptions: ["振込 ヤマダ タロウ", "振込 サトウ ハナコ", "振込 カ）ミライデザイン", "立替金 精算 タナカ"], min: 3000, max: 90000, weight: 5 },
  { category: "振込", direction: "out", descriptions: ["振込 家賃 サンコウ不動産", "振込 ススキ ケンタ", "振込 カ）クラウドワークス"], min: 8000, max: 120000, weight: 4 },
  { category: "引落", direction: "out", descriptions: ["口座振替 トウキョウ電力", "口座振替 トウキョウガス", "口座振替 NTTファイナンス", "口座振替 ジェイコム", "口座振替 国民年金"], min: 2200, max: 24000, weight: 7 },
  { category: "ATM出金", direction: "out", descriptions: ["ATM出金 セブン銀行", "ATM出金 当行ATM 渋谷", "ATM出金 ローソン銀行"], min: 5000, max: 50000, weight: 6 },
  { category: "カード", direction: "out", descriptions: ["カード利用 アマゾン", "カード利用 スターバックス", "カード利用 ユニクロ", "カード利用 JR東日本", "カード利用 マツモトキヨシ", "カード利用 Apple"], min: 480, max: 38000, weight: 9 },
  { category: "手数料", direction: "out", descriptions: ["振込手数料", "ATM時間外手数料"], min: 110, max: 770, weight: 3 },
  { category: "利息", direction: "in", descriptions: ["普通預金利息"], min: 8, max: 220, weight: 1 },
];

function pickTemplate(rand: () => number): Template {
  const total = TEMPLATES.reduce((s, t) => s + t.weight, 0);
  let r = rand() * total;
  for (const t of TEMPLATES) {
    r -= t.weight;
    if (r <= 0) return t;
  }
  return TEMPLATES[0];
}

export interface GeneratedLedger {
  transactions: Transaction[];
  openingBalance: number;
  periodStart: string; // yyyy-mm-dd of earliest txn
  periodEnd: string; // yyyy-mm-dd of latest txn
}

function isoDate(d: Date): string {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

/**
 * Generate ~`count` transactions ending at `anchorEnd`, then compute a running
 * balance forward from `openingBalance`. Returns transactions newest-first.
 */
export function generateLedger(opts: {
  anchorEnd: Date;
  daysBack?: number;
  count?: number;
  openingBalance?: number;
  seed?: number;
}): GeneratedLedger {
  const { anchorEnd, daysBack = 95, count = 52, openingBalance = 1_482_300, seed = 20260622 } = opts;
  const rand = mulberry32(seed);

  // Spread `count` transactions across `daysBack` days, oldest-first.
  const raw: Omit<Transaction, "balance" | "id">[] = [];
  for (let i = 0; i < count; i++) {
    const t = pickTemplate(rand);
    const dayOffset = Math.floor(rand() * daysBack);
    const d = new Date(anchorEnd);
    d.setDate(d.getDate() - dayOffset);
    const span = t.max - t.min;
    // round to a "money-ish" value
    const amount = Math.round((t.min + rand() * span) / 10) * 10;
    raw.push({
      date: isoDate(d),
      description: t.descriptions[Math.floor(rand() * t.descriptions.length)],
      category: t.category,
      direction: t.direction,
      amount,
    });
  }

  // chronological (oldest-first) for running balance
  raw.sort((a, b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0));

  let bal = openingBalance;
  const chrono: Transaction[] = raw.map((r, idx) => {
    bal += r.direction === "in" ? r.amount : -r.amount;
    return { ...r, id: `txn-${idx}`, balance: bal };
  });

  const periodStart = chrono[0]?.date ?? isoDate(anchorEnd);
  const periodEnd = chrono[chrono.length - 1]?.date ?? isoDate(anchorEnd);

  // newest-first for display
  const transactions = [...chrono].reverse();

  return { transactions, openingBalance, periodStart, periodEnd };
}

// --- summary over a (filtered) set ---------------------------------------
export interface LedgerSummary {
  totalIn: number;
  totalOut: number;
  /** Closing balance = balance of the most recent (newest) txn in the set. */
  closingBalance: number | null;
  count: number;
}

export function summarize(txns: Transaction[]): LedgerSummary {
  let totalIn = 0;
  let totalOut = 0;
  for (const t of txns) {
    if (t.direction === "in") totalIn += t.amount;
    else totalOut += t.amount;
  }
  // txns are newest-first; closing balance is the running balance of the
  // chronologically latest transaction = index 0.
  const closingBalance = txns.length ? txns[0].balance : null;
  return { totalIn, totalOut, closingBalance, count: txns.length };
}

// --- CSV export (no library helper exists for this) ----------------------
export function toCsv(txns: Transaction[]): string {
  const header = ["日付", "摘要", "カテゴリ", "出金", "入金", "残高"];
  const rows = txns.map((t) => [
    t.date,
    // escape quotes/commas
    `"${t.description.replace(/"/g, '""')}"`,
    t.category,
    t.direction === "out" ? String(t.amount) : "",
    t.direction === "in" ? String(t.amount) : "",
    String(t.balance),
  ]);
  // BOM so Excel reads UTF-8 (Japanese) correctly
  return "﻿" + [header, ...rows].map((r) => r.join(",")).join("\r\n");
}

"use client";

import * as React from "react";
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  DataTable,
  DateRangePicker,
  EmptyState,
  FilterButton,
  Label,
  RangeSlider,
  SearchInput,
  Skeleton,
  Statistic,
  ToggleGroup,
  ToggleGroupItem,
  formatCurrency,
  formatNumber,
  type ColumnDef,
} from "@gunjo/ui";
import { ja } from "date-fns/locale";
import type { DateRange } from "react-day-picker";
import {
  IconReceipt,
  IconDownload,
  IconFileTypeCsv,
  IconFileTypePdf,
  IconSearchOff,
} from "@tabler/icons-react";
import {
  CATEGORIES,
  CATEGORY_META,
  generateLedger,
  summarize,
  toCsv,
  type Transaction,
  type TxnCategory,
} from "./data";

// --- account / period constants ------------------------------------------
const ACCOUNT = {
  bank: "ぐんじょう銀行",
  branch: "渋谷支店 (店番 201)",
  type: "普通預金",
  number: "1234567",
  holder: "グンジョウ タロウ",
};

// Anchor "today" deterministically (matches currentDate in env) so SSR/CSR agree.
const TODAY = new Date(2026, 5, 22); // 2026-06-22 (month is 0-indexed)

const { transactions: ALL_TXNS, openingBalance: OPENING_BALANCE } = generateLedger({
  anchorEnd: TODAY,
  daysBack: 95,
  count: 52,
  openingBalance: 1_482_300,
});

// amount-range bounds derived from data
const MAX_AMOUNT = Math.ceil(
  Math.max(...ALL_TXNS.map((t) => t.amount)) / 10000
) * 10000;

type PeriodPreset = "thisMonth" | "lastMonth" | "all" | "custom";
type TypeFilter = "all" | "in" | "out";

function startOfMonth(d: Date) {
  return new Date(d.getFullYear(), d.getMonth(), 1);
}
function endOfMonth(d: Date) {
  return new Date(d.getFullYear(), d.getMonth() + 1, 0);
}
function toIso(d: Date) {
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${d.getFullYear()}-${m}-${day}`;
}

function presetRange(preset: PeriodPreset): { from?: string; to?: string } {
  if (preset === "thisMonth") {
    return { from: toIso(startOfMonth(TODAY)), to: toIso(endOfMonth(TODAY)) };
  }
  if (preset === "lastMonth") {
    const lm = new Date(TODAY.getFullYear(), TODAY.getMonth() - 1, 1);
    return { from: toIso(startOfMonth(lm)), to: toIso(endOfMonth(lm)) };
  }
  return {}; // all / custom resolved elsewhere
}

// Format a yyyy-mm-dd ISO string as Japanese short date without TZ drift.
function formatJpDate(iso: string): string {
  const [y, m, d] = iso.split("-");
  return `${y}/${m}/${d}`;
}

export default function TransactionsScreen() {
  // --- loading skeleton concept (brief mount delay) -----------------------
  const [loading, setLoading] = React.useState(true);
  React.useEffect(() => {
    const id = setTimeout(() => setLoading(false), 350);
    return () => clearTimeout(id);
  }, []);

  // --- filter state -------------------------------------------------------
  const [period, setPeriod] = React.useState<PeriodPreset>("all");
  const [customRange, setCustomRange] = React.useState<DateRange | undefined>(undefined);
  const [categories, setCategories] = React.useState<Set<string>>(new Set());
  const [type, setType] = React.useState<TypeFilter>("all");
  const [amountRange, setAmountRange] = React.useState<[number, number]>([0, MAX_AMOUNT]);
  const [query, setQuery] = React.useState("");

  // Resolve the active date window (ISO strings, inclusive) from preset/custom.
  const dateWindow = React.useMemo<{ from?: string; to?: string }>(() => {
    if (period === "custom") {
      return {
        from: customRange?.from ? toIso(customRange.from) : undefined,
        to: customRange?.to ? toIso(customRange.to) : undefined,
      };
    }
    if (period === "all") return {};
    return presetRange(period);
  }, [period, customRange]);

  // --- apply filters (AND) ------------------------------------------------
  const filtered = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    return ALL_TXNS.filter((t) => {
      if (dateWindow.from && t.date < dateWindow.from) return false;
      if (dateWindow.to && t.date > dateWindow.to) return false;
      if (categories.size > 0 && !categories.has(t.category)) return false;
      if (type !== "all" && t.direction !== type) return false;
      if (t.amount < amountRange[0] || t.amount > amountRange[1]) return false;
      if (q && !t.description.toLowerCase().includes(q) && !t.category.toLowerCase().includes(q)) return false;
      return true;
    });
  }, [dateWindow, categories, type, amountRange, query]);

  const summary = React.useMemo(() => summarize(filtered), [filtered]);

  const activeFilterCount =
    (period !== "all" ? 1 : 0) +
    (categories.size > 0 ? 1 : 0) +
    (type !== "all" ? 1 : 0) +
    (amountRange[0] !== 0 || amountRange[1] !== MAX_AMOUNT ? 1 : 0) +
    (query.trim() ? 1 : 0);

  const resetFilters = React.useCallback(() => {
    setPeriod("all");
    setCustomRange(undefined);
    setCategories(new Set());
    setType("all");
    setAmountRange([0, MAX_AMOUNT]);
    setQuery("");
  }, []);

  // --- export -------------------------------------------------------------
  const download = React.useCallback(
    (kind: "csv" | "pdf") => {
      if (kind === "csv") {
        const blob = new Blob([toCsv(filtered)], { type: "text/csv;charset=utf-8;" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `取引明細_${toIso(TODAY)}.csv`;
        a.click();
        URL.revokeObjectURL(url);
      } else {
        // No PDF helper in @gunjo/ui — fall back to print-to-PDF.
        window.print();
      }
    },
    [filtered]
  );

  // --- table columns ------------------------------------------------------
  const columns = React.useMemo<ColumnDef<Transaction>[]>(
    () => [
      {
        accessorKey: "date",
        header: "日付",
        size: 116,
        cell: ({ row }) => (
          <span className="tabular-nums whitespace-nowrap">{formatJpDate(row.original.date)}</span>
        ),
        sortingFn: "alphanumeric",
      },
      {
        accessorKey: "description",
        header: "摘要 (相手先)",
        enableSorting: false,
        cell: ({ row }) => (
          <span className="block truncate" title={row.original.description}>
            {row.original.description}
          </span>
        ),
      },
      {
        accessorKey: "category",
        header: "カテゴリ",
        size: 116,
        enableSorting: false,
        cell: ({ row }) => {
          const c = row.original.category as TxnCategory;
          return <Badge variant={CATEGORY_META[c].tone}>{c}</Badge>;
        },
      },
      {
        id: "out",
        header: () => <div className="text-right">出金</div>,
        accessorFn: (t) => (t.direction === "out" ? t.amount : 0),
        size: 132,
        cell: ({ row }) =>
          row.original.direction === "out" ? (
            <div className="text-right tabular-nums font-medium text-destructive">
              <span className="sr-only">出金 </span>−{formatCurrency(row.original.amount)}
            </div>
          ) : (
            <div className="text-right text-muted-foreground" aria-hidden="true">
              —
            </div>
          ),
      },
      {
        id: "in",
        header: () => <div className="text-right">入金</div>,
        accessorFn: (t) => (t.direction === "in" ? t.amount : 0),
        size: 132,
        cell: ({ row }) =>
          row.original.direction === "in" ? (
            <div className="text-right tabular-nums font-medium text-success">
              <span className="sr-only">入金 </span>＋{formatCurrency(row.original.amount)}
            </div>
          ) : (
            <div className="text-right text-muted-foreground" aria-hidden="true">
              —
            </div>
          ),
      },
      {
        accessorKey: "balance",
        header: () => <div className="text-right">残高</div>,
        size: 140,
        cell: ({ row }) => (
          <div className="text-right tabular-nums text-foreground">
            {formatCurrency(row.original.balance)}
          </div>
        ),
      },
    ],
    []
  );

  // --- render -------------------------------------------------------------
  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 lg:py-10">
      {/* skip-style heading */}
      <header className="mb-6">
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <IconReceipt className="h-4 w-4" aria-hidden="true" />
          <span>{ACCOUNT.bank}</span>
        </div>
        <h1 className="mt-1 text-2xl font-bold tracking-tight text-foreground">取引明細</h1>
        <p className="mt-1 text-sm text-muted-foreground">
          {ACCOUNT.branch}・{ACCOUNT.type}・口座番号 {ACCOUNT.number}（{ACCOUNT.holder} 様）
        </p>
      </header>

      {/* --- period + summary --------------------------------------------- */}
      <section aria-labelledby="summary-heading" className="mb-6">
        <h2 id="summary-heading" className="sr-only">
          口座サマリー
        </h2>
        {loading ? (
          <div className="grid grid-cols-2 gap-3 lg:grid-cols-4">
            {Array.from({ length: 4 }).map((_, i) => (
              <Card key={i}>
                <CardContent className="space-y-2 p-4">
                  <Skeleton className="h-3 w-20" />
                  <Skeleton className="h-7 w-28" />
                </CardContent>
              </Card>
            ))}
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-3 lg:grid-cols-4">
            <Statistic
              label="入金合計"
              value={formatCurrency(summary.totalIn)}
              tone="positive"
              hint={`${formatNumber(filtered.filter((t) => t.direction === "in").length)} 件`}
            />
            <Statistic
              label="出金合計"
              value={`−${formatCurrency(summary.totalOut).replace(/^[−-]/, "")}`}
              tone="negative"
              hint={`${formatNumber(filtered.filter((t) => t.direction === "out").length)} 件`}
            />
            <Statistic
              label="期末残高"
              value={summary.closingBalance !== null ? formatCurrency(summary.closingBalance) : "—"}
              hint={
                summary.count
                  ? `${formatJpDate(filtered[0].date)} 時点`
                  : "該当なし"
              }
            />
            <Statistic
              label="期首残高"
              value={formatCurrency(OPENING_BALANCE)}
              hint="期間開始時点"
            />
          </div>
        )}
      </section>

      {/* --- filters ------------------------------------------------------ */}
      <section aria-labelledby="filters-heading" className="mb-4">
        <h2 id="filters-heading" className="mb-3 text-sm font-semibold text-foreground">
          絞り込み
        </h2>

        <Card>
          <CardContent className="space-y-4 p-4">
            {/* row 1: search + type */}
            <div className="flex flex-col gap-3 md:flex-row md:items-end">
              <div className="min-w-0 flex-1">
                <Label htmlFor="txn-search" className="mb-1.5 block text-sm font-medium">
                  摘要・相手先で検索
                </Label>
                <SearchInput
                  id="txn-search"
                  value={query}
                  onValueChange={setQuery}
                  placeholder="例: アマゾン、給与、電力…"
                  aria-label="摘要・相手先で検索"
                />
              </div>
              <div>
                <span id="type-toggle-label" className="mb-1.5 block text-sm font-medium">
                  入出金
                </span>
                <ToggleGroup
                  type="single"
                  value={type}
                  disallowEmpty
                  onValueChange={(v) => setType((v as TypeFilter) || "all")}
                  aria-labelledby="type-toggle-label"
                  variant="outline"
                >
                  <ToggleGroupItem value="all" aria-label="すべて">
                    すべて
                  </ToggleGroupItem>
                  <ToggleGroupItem value="in" aria-label="入金のみ">
                    入金
                  </ToggleGroupItem>
                  <ToggleGroupItem value="out" aria-label="出金のみ">
                    出金
                  </ToggleGroupItem>
                </ToggleGroup>
              </div>
            </div>

            {/* row 2: period preset + custom range + category facet */}
            <div className="flex flex-col gap-3 md:flex-row md:items-end md:flex-wrap">
              <div>
                <span id="period-toggle-label" className="mb-1.5 block text-sm font-medium">
                  期間
                </span>
                <ToggleGroup
                  type="single"
                  value={period}
                  disallowEmpty
                  onValueChange={(v) => {
                    const p = (v as PeriodPreset) || "all";
                    setPeriod(p);
                    if (p !== "custom") setCustomRange(undefined);
                  }}
                  aria-labelledby="period-toggle-label"
                  variant="outline"
                >
                  <ToggleGroupItem value="all">全期間</ToggleGroupItem>
                  <ToggleGroupItem value="thisMonth">今月</ToggleGroupItem>
                  <ToggleGroupItem value="lastMonth">先月</ToggleGroupItem>
                  <ToggleGroupItem value="custom">期間指定</ToggleGroupItem>
                </ToggleGroup>
              </div>

              {period === "custom" && (
                <div>
                  <Label htmlFor="txn-range" className="mb-1.5 block text-sm font-medium">
                    開始日 – 終了日
                  </Label>
                  <DateRangePicker
                    id="txn-range"
                    value={customRange}
                    onValueChange={setCustomRange}
                    locale={ja}
                    dateFormat="yyyy/MM/dd"
                    placeholder="期間を選択"
                    calendarLabel="取引期間"
                  />
                </div>
              )}

              <div>
                <span className="mb-1.5 block text-sm font-medium">カテゴリ</span>
                <FilterButton
                  title="カテゴリ"
                  options={CATEGORIES.map((c) => ({ label: c, value: c }))}
                  selectedValues={categories}
                  onFilterChange={setCategories}
                  clearLabel="クリア"
                  selectedLabel={(n) => `${n}件選択中`}
                />
              </div>
            </div>

            {/* row 3: amount range */}
            <div className="max-w-md">
              <div className="mb-1.5 flex items-baseline justify-between">
                <span id="amount-range-label" className="text-sm font-medium">
                  金額レンジ
                </span>
                <span className="tabular-nums text-xs text-muted-foreground" aria-hidden="true">
                  {formatCurrency(amountRange[0])} – {formatCurrency(amountRange[1])}
                </span>
              </div>
              <RangeSlider
                value={amountRange}
                onValueChange={setAmountRange}
                min={0}
                max={MAX_AMOUNT}
                step={1000}
                aria-labelledby="amount-range-label"
                minLabel={`下限 ${formatCurrency(amountRange[0])}`}
                maxLabel={`上限 ${formatCurrency(amountRange[1])}`}
              />
            </div>

            {/* active-filter chips + clear */}
            {activeFilterCount > 0 && (
              <div className="flex flex-wrap items-center gap-2 border-t pt-3">
                <span className="text-xs text-muted-foreground">適用中:</span>
                {period !== "all" && (
                  <Badge variant="secondary">
                    期間:{" "}
                    {period === "thisMonth"
                      ? "今月"
                      : period === "lastMonth"
                      ? "先月"
                      : "指定"}
                  </Badge>
                )}
                {type !== "all" && (
                  <Badge variant="secondary">{type === "in" ? "入金のみ" : "出金のみ"}</Badge>
                )}
                {[...categories].map((c) => (
                  <Badge
                    key={c}
                    variant="secondary"
                    onRemove={() => {
                      const next = new Set(categories);
                      next.delete(c);
                      setCategories(next);
                    }}
                    removeLabel={`${c} を解除`}
                  >
                    {c}
                  </Badge>
                ))}
                {query.trim() && <Badge variant="secondary">「{query.trim()}」</Badge>}
                <Button variant="ghost" size="sm" onClick={resetFilters}>
                  すべて解除
                </Button>
              </div>
            )}
          </CardContent>
        </Card>
      </section>

      {/* --- results header: count + export ------------------------------- */}
      <section aria-labelledby="results-heading">
        <div className="mb-3 flex flex-wrap items-center justify-between gap-3">
          <h2 id="results-heading" className="text-sm font-semibold text-foreground">
            取引一覧
          </h2>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => download("csv")}
              disabled={filtered.length === 0}
            >
              <IconFileTypeCsv className="h-4 w-4" aria-hidden="true" />
              CSV
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => download("pdf")}
              disabled={filtered.length === 0}
            >
              <IconFileTypePdf className="h-4 w-4" aria-hidden="true" />
              PDF
            </Button>
          </div>
        </div>

        {/* polite live region announcing result count */}
        <p className="sr-only" role="status" aria-live="polite">
          {filtered.length} 件の取引が見つかりました
        </p>

        {loading ? (
          <div className="space-y-2 rounded-md border p-4">
            {Array.from({ length: 6 }).map((_, i) => (
              <div key={i} className="flex items-center gap-4">
                <Skeleton className="h-4 w-24" />
                <Skeleton className="h-4 flex-1" />
                <Skeleton className="h-4 w-20" />
                <Skeleton className="h-4 w-24" />
              </div>
            ))}
          </div>
        ) : filtered.length === 0 ? (
          <EmptyState
            icon={<IconSearchOff className="h-6 w-6" aria-hidden="true" />}
            title="該当する取引はありません"
            description="絞り込み条件を変更するか、条件をすべて解除してください。"
            action={
              <Button variant="outline" size="sm" onClick={resetFilters}>
                絞り込みを解除
              </Button>
            }
            headingLevel={3}
          />
        ) : (
          <>
            {/* Desktop / tablet: real data table (md and up) */}
            <div className="hidden md:block">
              <DataTable
                columns={columns}
                data={filtered}
                pageSize={15}
                pageSizeOptions={[15, 30, 50]}
                labels={{
                  paginationSummary: (from, to, total) => `${from}–${to} 件 / 全 ${total} 件`,
                  pageSummary: (cur, tot) => `${cur} / ${tot} ページ`,
                  rowsPerPage: "1ページの表示件数",
                  previous: "前のページ",
                  next: "次のページ",
                  firstPage: "最初のページ",
                  lastPage: "最後のページ",
                  sortAscending: "昇順で並び替え",
                  sortDescending: "降順で並び替え",
                  clearSort: "並び替えを解除",
                }}
              />
            </div>

            {/* Mobile (<md): card list (hand-rolled — see FINDINGS) */}
            <div className="md:hidden">
              <MobileCardList txns={filtered} />
            </div>
          </>
        )}
      </section>
    </main>
  );
}

// --- mobile card list ------------------------------------------------------
// Hand-rolled because DataTable hardcodes `min-w-[720px]` and does not collapse
// to cards. We page locally so mobile users don't scroll 50 cards.
function MobileCardList({ txns }: { txns: Transaction[] }) {
  const PAGE = 12;
  const [visible, setVisible] = React.useState(PAGE);
  React.useEffect(() => setVisible(PAGE), [txns]);
  const shown = txns.slice(0, visible);

  return (
    <div className="space-y-2">
      <p className="text-xs text-muted-foreground" aria-hidden="true">
        全 {formatNumber(txns.length)} 件中 {formatNumber(shown.length)} 件を表示
      </p>
      <ul className="space-y-2">
        {shown.map((t) => {
          const out = t.direction === "out";
          return (
            <li key={t.id}>
              <Card>
                <CardHeader className="flex-row items-center justify-between gap-2 space-y-0 p-3 pb-1">
                  <CardTitle as="p" className="text-xs font-normal text-muted-foreground tabular-nums">
                    {formatJpDate(t.date)}
                  </CardTitle>
                  <Badge variant={CATEGORY_META[t.category].tone}>{t.category}</Badge>
                </CardHeader>
                <CardContent className="space-y-1 p-3 pt-1">
                  <p className="truncate text-sm font-medium text-foreground" title={t.description}>
                    {t.description}
                  </p>
                  <div className="flex items-end justify-between gap-2">
                    <span
                      className={
                        "tabular-nums text-base font-semibold " +
                        (out ? "text-destructive" : "text-success")
                      }
                    >
                      <span className="sr-only">{out ? "出金" : "入金"} </span>
                      {out ? "−" : "＋"}
                      {formatCurrency(t.amount)}
                    </span>
                    <span className="text-right text-xs text-muted-foreground tabular-nums">
                      残高 {formatCurrency(t.balance)}
                    </span>
                  </div>
                </CardContent>
              </Card>
            </li>
          );
        })}
      </ul>
      {visible < txns.length && (
        <Button
          variant="outline"
          className="w-full"
          onClick={() => setVisible((v) => v + PAGE)}
        >
          <IconDownload className="h-4 w-4 rotate-90" aria-hidden="true" />
          さらに表示（残り {formatNumber(txns.length - visible)} 件）
        </Button>
      )}
    </div>
  );
}
